# scripts/validate_prompt.py
import yaml, jsonschema, sys
from pathlib import Path

PROMPT_SCHEMA = {
    "type": "object",
    "required": ["name", "version", "system", "parameters"],
    "additionalProperties": False,
    "properties": {
        "name":        {"type": "string", "pattern": "^[a-z][a-z0-9-]*$"},
        "version":     {"type": "string", "pattern": "^v\\d+(\\.\\d+)*$"},
        "description": {"type": "string"},
        "system":      {"type": "string", "minLength": 10},
        "examples": {
            "type": "array",
            "items": {
                "type": "object",
                "required": ["role", "content"],
                "properties": {
                    "role":    {"type": "string", "enum": ["user", "assistant"]},
                    "content": {"type": "string"},
                },
            },
        },
        "parameters": {
            "type": "object",
            "required": ["temperature", "max_tokens"],
            "properties": {
                "temperature": {"type": "number", "minimum": 0, "maximum": 1},
                "max_tokens":  {"type": "integer", "minimum": 1, "maximum": 8192},
                "top_p":       {"type": "number", "minimum": 0, "maximum": 1},
            },
        },
        "constraints": {"type": "array", "items": {"type": "string"}},
    },
}

def validate_prompt_file(path: str) -> None:
    with open(path) as f:
        prompt = yaml.safe_load(f)

    # Filename must match internal version field
    stem = Path(path).stem  # e.g. "v8"
    if prompt.get("version") != stem:
        raise ValueError(
            f"Filename '{stem}.yaml' does not match version field '{prompt.get('version')}'"
        )

    jsonschema.validate(prompt, PROMPT_SCHEMA)
    print(f"OK: {path}")

if __name__ == "__main__":
    for path in sys.argv[1:]:
        validate_prompt_file(path)

# scripts/prompt_diff.py
import yaml, difflib, sys

def load_system(yaml_path: str) -> str:
    with open(yaml_path) as f:
        return yaml.safe_load(f).get("system", "")

def diff_prompts(old_path: str, new_path: str) -> str:
    old_lines = load_system(old_path).splitlines(keepends=True)
    new_lines = load_system(new_path).splitlines(keepends=True)
    diff = difflib.unified_diff(
        old_lines, new_lines,
        fromfile=old_path, tofile=new_path,
        lineterm="",
    )
    return "".join(diff)

if __name__ == "__main__":
    print(diff_prompts(sys.argv[1], sys.argv[2]))

# tests/test_prompt_regression.py
import yaml, pytest, anthropic

client = anthropic.Anthropic()

GOLDEN = [
    {
        "query": "What is the return policy?",
        "context": ["Returns are accepted within 30 days of purchase."],
        "must_contain": ["30 days", "[Doc 1]"],
        "must_not_contain": ["I don't know", "As an AI"],
    },
    {
        "query": "What is the CEO's name?",
        "context": ["Acme Inc. was founded in 2010."],
        "must_contain": ["don't have that information"],
        "must_not_contain": [],
    },
]

def load_prompt(version: str) -> dict:
    with open(f"config/prompts/rag-assistant/{version}.yaml") as f:
        return yaml.safe_load(f)

@pytest.mark.parametrize("case", GOLDEN)
def test_prompt_v8_golden(case):
    prompt = load_prompt("v8")
    context_block = "\n".join(
        f"[Doc {i+1}] {p}" for i, p in enumerate(case["context"])
    )
    response = client.messages.create(
        model="claude-haiku-4-5-20251001",   # cheap model for regression tests
        max_tokens=256,
        messages=[
            {"role": "system", "content": prompt["system"]},
            {"role": "user", "content": f"Context:\n{context_block}\n\nQuestion: {case['query']}"},
        ],
    )
    text = response.content[0].text.lower()
    for expected in case["must_contain"]:
        assert expected.lower() in text, f"Missing '{expected}' in: {text}"
    for forbidden in case["must_not_contain"]:
        assert forbidden.lower() not in text, f"Forbidden '{forbidden}' in: {text}"

