    adapter: { name: rag-assistant-adapter, version: "14" }

from your_module import load_prompt

class RAGPipeline:
    def __init__(self):
        # Load all prompts once at startup; versions pinned via registry
        self.rewriter  = load_prompt("query-rewriter")
        self.grader    = load_prompt("retrieval-grader")
        self.generator = load_prompt("rag-assistant")

    def run(self, user_query: str) -> dict:
        rewritten = call_llm(self.rewriter, user_query)
        passages  = retrieve(rewritten)
        graded    = [p for p in passages if grade(self.grader, p) > 0.6]
        answer    = call_llm(self.generator, user_query, graded)
        return {
            "answer": answer,
            "versions": {
                "rewriter":  self.rewriter["version"],
                "grader":    self.grader["version"],
                "generator": self.generator["version"],
            },
        }

from your_module import flag_store, load_prompt

def get_active_prompt(name: str) -> dict:
    # Check for a flag override before falling back to registry
    flag_key = f"prompt_version_override_{name}"
    override = flag_store.get(flag_key)
    if override:
        return load_prompt(name, version=override)
    return load_prompt(name, stage="Production")

